QuestTranslator_BookData = {
    ["Admiral Barean Westwind"] = {
        ["Title"] = "Amiral Barean Westwind",
        ["Text"] = "Amiral Barean WestwindNEW_LINEKızıl Filo'nun Büyük AmiraliNEW_LINEKul'Tiras VatandaşıNEW_LINENorthrend'in Donmuş Kıyılarında Kayboldu"
